import { z } from "zod";
import { PROVIDER_NAMES } from "../adapters.ts";

export const GlobalConfigSchema = z.object({
    provider: z.enum(PROVIDER_NAMES as unknown as ["anthropic", "openrouter"]).default("anthropic"),
    model: z.string().default("anthropic/claude-haiku-4-6"),
    models: z.array(z.string()).default([
        "claude-opus-4-5",
        "claude-sonnet-4-5",
        "claude-haiku-4-6",
    ]),
    summaryLength: z.number().positive().default(72),
    historyCount: z.number().positive().default(10),
});

export const DEFAULT_SCOPES = [
    "ui",
    "api",
    "config",
    "auth",
    "ci",
    "build",
    "docs",
    "test",
] as const;

export const DEFAULT_COMMIT_TYPES = [
    "feat",
    "fix",
    "docs",
    "style",
    "refactor",
    "test",
    "chore",
    "ci",
    "perf",
    "revert",
] as const;

export const RepoConfigSchema = z.object({
    issuePattern: z.string().optional(),
    issuePrefix: z.string().optional(),
    useLazygit: z.boolean().default(true),
    commitTypes: z.array(z.string()).default([...DEFAULT_COMMIT_TYPES]),
    scopes: z.array(z.string()).default([...DEFAULT_SCOPES]),
});

export const MergedConfigSchema = z.object({
    ...GlobalConfigSchema.shape,
    ...RepoConfigSchema.shape,
});

export type GlobalConfig = z.infer<typeof GlobalConfigSchema>;
export type RepoConfig = z.infer<typeof RepoConfigSchema>;
export type MergedConfig = z.infer<typeof MergedConfigSchema>;

import { chat } from "@tanstack/ai";
import { createAdapter, type ModelName, type ProviderName } from "../adapters.ts";

export async function generate(
    prompt: string,
    model: ModelName,
    provider: ProviderName,
): Promise<string> {
    const adapter = createAdapter(provider, model);

    const stream = chat({
        adapter,
        messages: [{ role: "user", content: prompt }],
    });

    let text = "";
    for await (const chunk of stream) {
        if (chunk.type === "RUN_ERROR") {
            throw new Error(chunk.error.message);
        }
        if (chunk.type === "TEXT_MESSAGE_CONTENT") {
            text += chunk.delta;
        }
    }

    return text.trim();
}

import { ANTHROPIC_MODELS, type AnthropicChatModel, anthropicText } from "@tanstack/ai-anthropic";
import { openRouterText } from "@tanstack/ai-openrouter";

export { ANTHROPIC_MODELS };

type OpenRouterModel = Parameters<typeof openRouterText>[0];

export const PROVIDER_NAMES = ["anthropic", "openrouter"] as const;

export type ProviderName = (typeof PROVIDER_NAMES)[number];

export type ModelName = AnthropicChatModel | OpenRouterModel | string;

export const OPENROUTER_DEFAULT_MODELS = [
    "google/gemma-3-27b-it",
    "google/gemma-3-12b-it",
    "nvidia/nemotron-nano-9b-v2",
] as const;

export function createAdapter(provider: ProviderName, model: ModelName) {
    switch (provider) {
        case "anthropic":
            return anthropicText(model as AnthropicChatModel);
        case "openrouter":
            return openRouterText(model as OpenRouterModel);
        default: {
            const _exhaustive: never = provider;
            throw new Error(`Unknown provider: ${_exhaustive}`);
        }
    }
}

import { Confirm, Select } from "@cliffy/prompt";

export async function selectCommitAction(): Promise<"commit" | "regenerate" | "edit" | "cancel"> {
    return await Select.prompt({
        message: "What would you like to do?",
        options: [
            { name: "Commit", value: "commit" },
            { name: "Regenerate", value: "regenerate" },
            { name: "Edit", value: "edit" },
            { name: "Cancel", value: "cancel" },
        ],
    }) as "commit" | "regenerate" | "edit" | "cancel";
}

export async function selectBranchAction(): Promise<"create" | "regenerate" | "cancel"> {
    return await Select.prompt({
        message: "What would you like to do?",
        options: [
            { name: "Create Branch", value: "create" },
            { name: "Regenerate", value: "regenerate" },
            { name: "Cancel", value: "cancel" },
        ],
    }) as "create" | "regenerate" | "cancel";
}

export async function selectModel<T extends string>(models: T[]): Promise<T> {
    return await Select.prompt({
        message: "Select model for regeneration:",
        options: models.map((m) => ({ name: m, value: m })),
    }) as T;
}

export async function confirmForcePush(): Promise<boolean> {
    return await Confirm.prompt("Force push with --force-with-lease?");
}

export async function openInEditor(content: string): Promise<string | null> {
    const tmpFile = await Deno.makeTempFile({ suffix: ".txt" });
    await Deno.writeTextFile(tmpFile, content);

    const editor = Deno.env.get("EDITOR") ?? "nvim";
    const command = new Deno.Command(editor, {
        args: [tmpFile],
        stdin: "inherit",
        stdout: "inherit",
        stderr: "inherit",
    });

    const process = command.spawn();
    const status = await process.status;

    if (!status.success) {
        await Deno.remove(tmpFile).catch(() => {});
        return null;
    }

    try {
        const result = (await Deno.readTextFile(tmpFile)).trim();
        return result || null;
    } finally {
        await Deno.remove(tmpFile).catch(() => {});
    }
}

export function editMessage(message: string): Promise<string | null> {
    return openInEditor(message);
}

import { Confirm, Input, Select } from "@cliffy/prompt";
import * as colors from "./colors.ts";
import type { MergedConfig } from "../config/schema.ts";
import { openInEditor } from "./prompts.ts";
import { commit } from "../git/operations.ts";

export interface CommitParts {
    type: string;
    scope: string;
    breaking: boolean;
    subject: string;
    body: string;
    footer: string;
}

export function buildCommitMessage(parts: CommitParts): string {
    const { type, scope, breaking, subject, body, footer } = parts;

    const scopePart = scope ? `(${scope})` : "";
    const breakingPart = breaking ? "!" : "";
    let message = `${type}${scopePart}${breakingPart}: ${subject}`;

    if (body) message += `\n\n${body}`;
    if (footer) message += `\n\n${footer}`;

    return message;
}

const CUSTOM_OPTION = "✏ custom...";

async function selectWithCustom(message: string, options: string[]): Promise<string> {
    const selected = await Select.prompt({
        message,
        search: true,
        options: [...options.map((o) => ({ name: o, value: o })), {
            name: CUSTOM_OPTION,
            value: CUSTOM_OPTION,
        }],
    }) as string;

    if (selected === CUSTOM_OPTION) {
        return await Input.prompt({ message: `${message} (custom)` });
    }

    return selected;
}

async function promptWithEditorEscape(message: string, initial = ""): Promise<string> {
    const value = await Input.prompt({
        message: `${message} (enter :e to open in $EDITOR)`,
        default: initial,
    });

    if (value === "\x07" || value.trim() === ":e") {
        const edited = await openInEditor(initial);
        return edited ?? initial;
    }

    return value;
}

export async function runGuidedCommit(config: MergedConfig): Promise<void> {
    try {
        await _runGuidedCommit(config);
    } catch (e) {
        if (e instanceof Error && e.message.includes("Interrupted")) {
            console.log("\nCommit cancelled.");
            Deno.exit(1);
        }
        throw e;
    }
}

async function _runGuidedCommit(config: MergedConfig): Promise<void> {
    // 1. Type
    const type = await selectWithCustom("Select commit type", config.commitTypes);

    // 2. Scope
    const scopeRaw = await selectWithCustom("Select scope (Enter to skip)", [
        "(none)",
        ...config.scopes,
    ]);
    const scope = scopeRaw === "(none)" ? "" : scopeRaw;

    // 3. Breaking change
    const breaking = await Confirm.prompt({
        message: "Breaking change?",
        default: false,
    });

    // 4. Subject
    let subject = "";
    while (!subject.trim()) {
        subject = await promptWithEditorEscape("Short description");
        if (!subject.trim()) {
            console.error(colors.red("Subject cannot be empty."));
        }
    }

    // 5. Body
    const body = await promptWithEditorEscape("Body (optional, Enter to skip)");

    // 6. Footer
    const footer = await promptWithEditorEscape(
        "Footer (optional — BREAKING CHANGE: ..., Closes #N)",
    );

    // 7. Preview
    const message = buildCommitMessage({
        type,
        scope: scope.trim(),
        breaking,
        subject: subject.trim(),
        body: body.trim(),
        footer: footer.trim(),
    });

    console.log("");
    console.log("Commit message:");
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(message));
    console.log(colors.dim("─".repeat(40)));
    console.log("");

    // 8. Confirm
    const confirmed = await Confirm.prompt({ message: "Commit?", default: true });
    if (!confirmed) {
        console.log("Commit cancelled.");
        Deno.exit(1);
    }

    await commit(message);
    console.log(colors.green("\nChanges committed successfully!"));
}

